# extract_persona_requirements.py
# Reads interview transcripts and groups requirements by persona
import re
from collections import defaultdict
from pathlib import Path

PERSONA_KEYWORDS = {
    "novice": ["beginner", "first time", "confused", "don't understand", "help me"],
    "expert": ["quickly", "shortcut", "skip", "just do it", "already know"],
    "mobile": ["phone", "tap", "swipe", "small screen", "on the go"],
    "api": ["integrate", "programmatic", "JSON", "webhook", "batch"],
}

def extract_persona_requirements(transcript_dir: str) -> dict[str, list[str]]:
    requirements = defaultdict(list)
    for path in Path(transcript_dir).glob("*.txt"):
        text = path.read_text().lower()
        for line in text.splitlines():
            for persona, keywords in PERSONA_KEYWORDS.items():
                if any(kw in line for kw in keywords):
                    requirements[persona].append(line.strip())
    return dict(requirements)

if __name__ == "__main__":
    reqs = extract_persona_requirements("interviews/")
    for persona, lines in reqs.items():
        print(f"\n=== {persona.upper()} ({len(lines)} signals) ===")
        for line in lines[:5]:
            print(f"  - {line}")
